function blankState(){return {version:1,records:[],people:[],baseline:{start:serviceYearStart(),normalMinutes:parseTime('424:20'),extraMinutes:parseTime('71:00'),note:'移行累計'},favorites:Object.fromEntries(MEDIA.slice(0,20).map(x=>[x[0],true])),recent:[],firebaseConfig:FIREBASE_CONFIG,updatedAt:Date.now()};}
function normalizeRecord(r){ if(!r) return null; const activity=r.activityType||r.activity||'戸別'; const extra=/大会|メンテ|付加|災害/.test(activity); return {id:r.id||uid(),date:r.date||today(),activityType:activity,normalMinutes:parseTime(r.normalMinutes ?? (extra?0:r.minutes)),extraMinutes:parseTime(r.extraMinutes ?? (extra?r.minutes:0)),personId:r.personId||'',personName:r.personName||r.contactName||r.name||'',gender:r.gender||'',ageGroup:r.ageGroup||'',territory:r.territory||'',block:r.block||'',building:r.building||'',address:r.address||'',lat:r.lat??r.latitude??null,lng:r.lng??r.longitude??null,rvStatus:r.rvStatus||'関心あり',nextDate:r.nextDate||'',topics:Array.isArray(r.topics)?r.topics:[],lessonStatus:r.lessonStatus||'なし',lessonMaterial:r.lessonMaterial||'',lessonNo:r.lessonNo||'',media:Array.isArray(r.media)?r.media:[...(r.publications||[]),...(r.videos||[])].map(x=>typeof x==='string'?x:x.id).filter(Boolean),memo:r.memo||'',createdAt:r.createdAt||Date.now(),updatedAt:r.updatedAt||Date.now()}; }
function normalizePerson(p){ if(!p) return null; return {id:p.id||uid(),name:p.name||p.personName||p.contactName||'名前未入力',gender:p.gender||'',ageGroup:p.ageGroup||'',territory:p.territory||'',block:p.block||'',building:p.building||'',address:p.address||'',lat:p.lat??p.latitude??null,lng:p.lng??p.longitude??null,rvStatus:p.rvStatus||'関心あり',nextDate:p.nextDate||'',topics:Array.isArray(p.topics)?p.topics:[],lessonStatus:p.lessonStatus||'なし',lessonMaterial:p.lessonMaterial||'',lessonNo:p.lessonNo||'',memo:p.memo||'',createdAt:p.createdAt||Date.now(),updatedAt:p.updatedAt||Date.now()}; }
function normalizeState(s){s=s||{}; const n=blankState(); n.records=(s.records||[]).map(normalizeRecord).filter(Boolean); n.people=(s.people||[]).map(normalizePerson).filter(Boolean); n.baseline={start:(s.baseline&&s.baseline.start)||serviceYearStart(),normalMinutes:parseTime(s.baseline?.normalMinutes??s.baseline?.serviceMinutes??s.baseline?.minutes??n.baseline.normalMinutes),extraMinutes:parseTime(s.baseline?.extraMinutes??n.baseline.extraMinutes),note:s.baseline?.note||n.baseline.note}; n.favorites=s.favorites||n.favorites; n.recent=Array.isArray(s.recent)?s.recent:[]; n.firebaseConfig=s.firebaseConfig||FIREBASE_CONFIG; ensurePeople(n); return n;}
function personKey(p){return [p.name||'',p.address||'',p.building||''].join('|').trim();}
function ensurePeople(s){const byKey=new Map(s.people.map(p=>[personKey(p),p])); for(const r of s.records){if(!r.personName&&!r.address) continue; let p=r.personId?s.people.find(x=>x.id===r.personId):null; if(!p){let key=personKey({name:r.personName,address:r.address,building:r.building}); p=byKey.get(key);}
 if(!p){p=normalizePerson({...r,name:r.personName||'名前未入力'}); s.people.push(p); byKey.set(personKey(p),p);} r.personId=p.id;}}
function loadState(){let raw=localStorage.getItem(STORE_KEY); if(raw){try{return normalizeState(JSON.parse(raw));}catch(e){console.warn(e)}} const fresh=blankState(); return fresh;}
let state=loadState(), editingId=null, currentNormal=0, currentExtra=0, currentLat=null, currentLng=null, selectedMedia=[], map=null, markers=[], auth=null, db=null, user=null;
function saveLocal(){state.updatedAt=Date.now(); localStorage.setItem(STORE_KEY,JSON.stringify(state));}
function sums(){const m=today().slice(0,7), st=state.baseline.start||serviceYearStart(); let mn=0,me=0,yn=state.baseline.normalMinutes||0,ye=state.baseline.extraMinutes||0; for(const r of state.records){if((r.date||'').slice(0,7)===m){mn+=r.normalMinutes;me+=r.extraMinutes} if((r.date||'')>=st){yn+=r.normalMinutes;ye+=r.extraMinutes}} return {mn,me,yn,ye};}
function renderSummary(){const x=sums(); $('#monthNormal').textContent=fmt(x.mn); $('#monthExtra').textContent=fmt(x.me); $('#monthTotal').textContent=fmt(x.mn+x.me); $('#yearNormal').textContent=fmt(x.yn); $('#yearExtra').textContent=fmt(x.ye); $('#yearTotal').textContent=fmt(x.yn+x.ye); $('#personCount').textContent=state.people.length; $('#lessonCount').textContent=state.people.filter(p=>p.lessonStatus==='レッスン中').length;}
function setTab(t){$$('[data-tab]').forEach(b=>b.classList.toggle('active',b.dataset.tab===t)); $$('.panel').forEach(p=>p.classList.toggle('active',p.id==='tab-'+t)); if(t==='map') setTimeout(renderMap,100);}
function setTimes(n,e){currentNormal=Math.max(0,n||0);currentExtra=Math.max(0,e||0); $('#normalDisplay').textContent=fmt(currentNormal); $('#extraDisplay').textContent=fmt(currentExtra);}
function getTopics(){return $$('.topic:checked').map(x=>x.value)}
function setTopics(vals=[]){$$('.topic').forEach(x=>x.checked=vals.includes(x.value))}
function getRecordFromForm(){return normalizeRecord({id:editingId||uid(),date:$('#date').value||today(),activityType:$('#activityType').value,normalMinutes:currentNormal,extraMinutes:currentExtra,personId:$('#personSelect').value,personName:$('#personName').value.trim(),gender:$('#gender').value,ageGroup:$('#ageGroup').value,territory:$('#territory').value.trim(),block:$('#block').value,building:$('#building').value.trim(),address:$('#address').value.trim(),lat:currentLat,lng:currentLng,rvStatus:$('#rvStatus').value,nextDate:$('#nextDate').value,topics:getTopics(),lessonStatus:$('#lessonStatus').value,lessonMaterial:$('#lessonMaterial').value.trim(),lessonNo:$('#lessonNo').value.trim(),media:selectedMedia,memo:$('#memo').value.trim(),createdAt:editingId?(state.records.find(r=>r.id===editingId)?.createdAt||Date.now()):Date.now(),updatedAt:Date.now()});}
function upsertPerson(r){if(!$('#saveToPerson').checked) return r.personId; if(!r.personName&&!r.address) return r.personId; let p=r.personId?state.people.find(x=>x.id===r.personId):null; if(!p){const key=personKey({name:r.personName,address:r.address,building:r.building}); p=state.people.find(x=>personKey(x)===key);} if(!p){p=normalizePerson({name:r.personName||'名前未入力'}); state.people.push(p);} Object.assign(p,{name:r.personName||p.name,gender:r.gender||p.gender,ageGroup:r.ageGroup||p.ageGroup,territory:r.territory||p.territory,block:r.block||p.block,building:r.building||p.building,address:r.address||p.address,lat:r.lat??p.lat,lng:r.lng??p.lng,rvStatus:r.rvStatus,nextDate:r.nextDate,topics:r.topics,lessonStatus:r.lessonStatus,lessonMaterial:r.lessonMaterial,lessonNo:r.lessonNo,memo:r.memo||p.memo,updatedAt:Date.now()}); return p.id;}
function clearForm(){editingId=null; $('#date').value=today(); $('#activityType').value='戸別'; setTimes(0,0); selectedMedia=[]; renderSelectedMedia(); ['personName','gender','ageGroup','territory','block','building','address','nextDate','lessonMaterial','lessonNo','memo'].forEach(id=>$('#'+id).value=''); $('#personSelect').value=''; $('#rvStatus').value='関心あり'; $('#lessonStatus').value='なし'; setTopics([]); currentLat=null; currentLng=null; $('#saveBtn').textContent='記録を保存';}
function saveRecord(){const r=getRecordFromForm(); r.personId=upsertPerson(r); const i=state.records.findIndex(x=>x.id===r.id); if(i>=0) state.records[i]=r; else state.records.push(r); selectedMedia.forEach(id=>{state.recent=[id,...state.recent.filter(x=>x!==id)].slice(0,30)}); saveLocal(); clearForm(); renderAll(); alert('保存しました');}
function fillForm(r){editingId=r.id; $('#date').value=r.date; $('#activityType').value=r.activityType; setTimes(r.normalMinutes,r.extraMinutes); $('#personSelect').value=r.personId||''; ['personName','gender','ageGroup','territory','block','building','address','rvStatus','nextDate','lessonStatus','lessonMaterial','lessonNo','memo'].forEach(id=>{$('#'+id).value=r[id]||''}); currentLat=r.lat; currentLng=r.lng; selectedMedia=[...(r.media||[])]; setTopics(r.topics||[]); renderSelectedMedia(); $('#saveBtn').textContent='更新する'; setTab('record'); scrollTo({top:0,behavior:'smooth'});}
function applyPerson(id){const p=state.people.find(x=>x.id===id); if(!p) return; ['name','gender','ageGroup','territory','block','building','address','rvStatus','nextDate','lessonStatus','lessonMaterial','lessonNo','memo'].forEach(k=>{const id2=k==='name'?'personName':k; if($('#'+id2)) $('#'+id2).value=p[k]||''}); currentLat=p.lat; currentLng=p.lng; setTopics(p.topics||[]);}
function mediaById(id){return MEDIA.find(x=>x[0]===id)}
function cardHTML(m, selectMode=false){
  const on=selectedMedia.includes(m[0]);
  const thumb=m[4]||m[5]||'';
  const imageHtml=thumb?`<img class="thumb-img" src="${thumb}" alt="${esc(m[3]||'')}" loading="lazy" onerror="this.style.display='none';this.nextElementSibling.style.display='flex';"><div class="media-placeholder" style="display:none">${esc(m[2]||'')}</div>`:`<div class="media-placeholder">${esc(m[2]||'')}</div>`;
  return `<button class="media-card ${on?'selected':''}" data-media-id="${m[0]}" type="button">${imageHtml}<span class="media-kind">${esc(m[2]||'')}</span><b>${esc(m[3]||'')}</b>${selectMode?'<em>'+(on?'選択中':'選択')+'</em>':''}</button>`;
}
function renderSelectedMedia(){const box=$('#selectedMedia'); if(!box) return; box.innerHTML=selectedMedia.length?selectedMedia.map(id=>{const m=mediaById(id); return m?`<span class="pill-thumb"><img src="${m[4]}">${esc(m[3])}<button type="button" data-remove-media="${id}">×</button></span>`:''}).join(''):'<span class="muted">未選択</span>';}
function mediaFilterList(){let q=($('#mediaSearch')?.value||'').toLowerCase(); let kind=$('#mediaKind')?.value||'all'; return MEDIA.filter(m=>(kind==='all'||m[1]===kind||m[2]===kind)&&(m[3]+m[2]).toLowerCase().includes(q));}
function renderLibrary(){if(!$('#libraryGrid')) return; $('#libraryGrid').innerHTML=mediaFilterList().map(m=>cardHTML(m,true)).join('');}
function renderPeople(){const q=($('#peopleSearch')?.value||'').toLowerCase(); const rows=state.people.filter(p=>JSON.stringify(p).toLowerCase().includes(q)).sort((a,b)=>(a.nextDate||'9999').localeCompare(b.nextDate||'9999')); $('#peopleList').innerHTML=rows.length?rows.map(p=>{const recs=state.records.filter(r=>r.personId===p.id); const media=[...new Set(recs.flatMap(r=>r.media||[]))].slice(0,6); return `<div class="person-row"><div><h3>${esc(p.name)} ${p.lessonStatus==='レッスン中'?'<span class="badge">レッスン中</span>':''}</h3><p>${esc([p.gender,p.ageGroup,p.territory,p.block].filter(Boolean).join(' / '))}</p><p>${esc(p.address||'')} ${esc(p.building||'')}</p><p>次回: ${esc(p.nextDate||'未定')} / 履歴 ${recs.length}件</p><div class="mini-media">${media.map(id=>{const m=mediaById(id);return m?`<img title="${esc(m[3])}" src="${m[4]}">`:''}).join('')}</div></div><div class="row-actions"><button data-person-record="${p.id}">記録</button><button data-person-detail="${p.id}">詳細</button><button data-person-edit="${p.id}">編集</button></div></div>`}).join(''):'<p class="muted">人物はまだありません。記録保存時に自動登録できます。</p>';}
function showPersonDetail(id){const p=state.people.find(x=>x.id===id); if(!p) return; const recs=state.records.filter(r=>r.personId===id).sort((a,b)=>(b.date||'').localeCompare(a.date||'')); $('#detailContent').innerHTML=`<h3>${esc(p.name)}</h3><p>${esc([p.gender,p.ageGroup,p.territory,p.block].filter(Boolean).join(' / '))}</p><p>${esc(p.address||'')} ${esc(p.building||'')}</p><p>次回: ${esc(p.nextDate||'未定')} / ${esc(p.lessonStatus||'')}</p><hr>${recs.map(r=>`<div class="detail-rec"><b>${esc(r.date)} ${esc(r.activityType)} 通常${fmt(r.normalMinutes)} 付加${fmt(r.extraMinutes)}</b><p>${esc(r.memo||'')}</p><div class="mini-media">${(r.media||[]).map(id=>{const m=mediaById(id); return m?`<img title="${esc(m[3])}" src="${m[4]}">`:''}).join('')}</div></div>`).join('')||'<p>履歴なし</p>'}`; setTab('detail');}
function renderHistory(){const q=($('#historySearch')?.value||'').toLowerCase(); const rows=state.records.filter(r=>JSON.stringify(r).toLowerCase().includes(q)).sort((a,b)=>(b.date||'').localeCompare(a.date||'')||(b.createdAt||0)-(a.createdAt||0)); $('#historyList').innerHTML=rows.length?rows.map(r=>`<div class="history-row"><div><b>${esc(r.date)} ${esc(r.activityType)} 通常${fmt(r.normalMinutes)} 付加${fmt(r.extraMinutes)}</b><p>${esc(r.personName||'')} ${esc(r.gender||'')} ${esc(r.ageGroup||'')}</p><p>${esc([r.territory,r.block,r.address,r.building].filter(Boolean).join(' / '))}</p><div class="mini-media">${(r.media||[]).map(id=>{const m=mediaById(id);return m?`<img title="${esc(m[3])}" src="${m[4]}">`:''}).join('')}</div></div><div class="row-actions"><button data-rec-edit="${r.id}">編集</button><button class="danger" data-rec-delete="${r.id}">削除</button></div></div>`).join(''):'<p class="muted">履歴はありません。</p>';}
function renderPersonSelect(){const sel=$('#personSelect'); const cur=sel.value; sel.innerHTML='<option value="">新規または未選択</option>'+state.people.map(p=>`<option value="${p.id}">${esc(p.name)}${p.territory?' / '+esc(p.territory):''}</option>`).join(''); sel.value=cur;}
function renderStats(){const by={}; for(const r of state.records){const m=(r.date||'').slice(0,7)||'未日付'; by[m]??={n:0,e:0,c:0}; by[m].n+=r.normalMinutes; by[m].e+=r.extraMinutes; by[m].c++;} $('#statsBox').innerHTML='<table><tr><th>月</th><th>通常</th><th>付加</th><th>合計</th><th>件数</th></tr>'+Object.entries(by).sort().reverse().map(([m,x])=>`<tr><td>${m}</td><td>${fmt(x.n)}</td><td>${fmt(x.e)}</td><td>${fmt(x.n+x.e)}</td><td>${x.c}</td></tr>`).join('')+'</table>';}
function renderBaseline(){ $('#baseStart').value=state.baseline.start||serviceYearStart(); $('#baseNormal').value=fmt(state.baseline.normalMinutes||0); $('#baseExtra').value=fmt(state.baseline.extraMinutes||0); $('#baseNote').value=state.baseline.note||'';}
function renderAll(){renderSummary();renderPersonSelect();renderSelectedMedia();renderLibrary();renderPeople();renderHistory();renderStats();renderBaseline(); if($('#tab-map').classList.contains('active')) renderMap();}
function saveBaseline(){state.baseline={start:$('#baseStart').value||serviceYearStart(),normalMinutes:parseTime($('#baseNormal').value),extraMinutes:parseTime($('#baseExtra').value),note:$('#baseNote').value}; saveLocal(); renderAll(); alert('保存しました');}
async function geocodeAddress(){const addr=$('#address').value.trim(); if(!addr){alert('住所を入力してください');return;} try{const res=await fetch('https://nominatim.openstreetmap.org/search?format=json&limit=1&q='+encodeURIComponent(addr)); const arr=await res.json(); if(!arr.length){alert('見つかりませんでした');return;} currentLat=+arr[0].lat; currentLng=+arr[0].lon; alert('ピン位置を取得しました');}catch(e){alert('住所検索に失敗しました');}}
function useLocation(){if(!navigator.geolocation){alert('位置情報が使えません');return;} navigator.geolocation.getCurrentPosition(p=>{currentLat=p.coords.latitude;currentLng=p.coords.longitude;alert('現在地を取得しました');},e=>alert(e.message),{enableHighAccuracy:true,timeout:10000});}
function openMap(){const addr=$('#address').value.trim(); const q=currentLat&&currentLng?`${currentLat},${currentLng}`:addr; if(!q){alert('住所か位置が必要です');return;} open('https://www.google.com/maps/search/?api=1&query='+encodeURIComponent(q),'_blank');}
function renderMap(){if(!window.L)return; if(!map){map=L.map('map').setView([34.7108,137.7261],12); L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,attribution:'&copy; OpenStreetMap'}).addTo(map);} markers.forEach(m=>m.remove()); markers=[]; const pts=state.people.filter(p=>p.lat&&p.lng); pts.forEach(p=>markers.push(L.marker([p.lat,p.lng]).addTo(map).bindPopup(`<b>${esc(p.name)}</b><br>${esc(p.address||'')}<br>次回:${esc(p.nextDate||'未定')}`))); if(pts.length) map.fitBounds(pts.map(p=>[p.lat,p.lng]),{padding:[30,30]}); setTimeout(()=>map.invalidateSize(),100);}
function exportJson(){const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([JSON.stringify(state,null,2)],{type:'application/json'})); a.download='ministry-hub-backup.json'; a.click();}
async function importJson(file){const incoming=normalizeState(JSON.parse(await file.text())); if(!confirm('バックアップを現在のデータと統合しますか？'))return; const rec=new Map(state.records.map(r=>[r.id,r])); incoming.records.forEach(r=>rec.set(r.id,r)); const ppl=new Map(state.people.map(p=>[p.id,p])); incoming.people.forEach(p=>ppl.set(p.id,p)); state=normalizeState({...state,records:[...rec.values()],people:[...ppl.values()],baseline:incoming.baseline||state.baseline,favorites:{...state.favorites,...incoming.favorites}}); saveLocal(); renderAll(); alert('復元しました');}
function initFirebase(){try{const cfg=state.firebaseConfig||FIREBASE_CONFIG; $('#firebaseConfig').value=JSON.stringify(cfg,null,2); if(!firebase.apps.length) firebase.initializeApp(cfg); auth=firebase.auth(); db=firebase.firestore(); auth.onAuthStateChanged(u=>{user=u; $('#loginBtn').hidden=!!u; $('#logoutBtn').hidden=!u; $('#syncStatus').textContent=u?'同期準備OK: '+(u.email||''): '未ログイン';});}catch(e){$('#syncStatus').textContent='Firebase設定エラー: '+e.message;}}
async function cloudPush(){if(!user||!db){alert('先にログインしてください');return;} await db.collection('users').doc(user.uid).collection('apps').doc('ministryHubFinalSafe').set({state,updatedAt:firebase.firestore.FieldValue.serverTimestamp()}); alert('クラウドへ保存しました');}
async function cloudPull(){if(!user||!db){alert('先にログインしてください');return;} const snap=await db.collection('users').doc(user.uid).collection('apps').doc('ministryHubFinalSafe').get(); if(!snap.exists){alert('クラウドにデータがありません');return;} if(!confirm('クラウドから読み込み、端末データと統合しますか？'))return; const incoming=normalizeState(snap.data().state); const rec=new Map(state.records.map(r=>[r.id,r])); incoming.records.forEach(r=>rec.set(r.id,r)); const ppl=new Map(state.people.map(p=>[p.id,p])); incoming.people.forEach(p=>ppl.set(p.id,p)); state=normalizeState({...state,records:[...rec.values()],people:[...ppl.values()],baseline:incoming.baseline||state.baseline,favorites:{...state.favorites,...incoming.favorites}}); saveLocal(); renderAll(); alert('読み込みました');}
function bind(){ $('#tabs').addEventListener('click',e=>{if(e.target.dataset.tab)setTab(e.target.dataset.tab)}); document.body.addEventListener('click',e=>{const b=e.target.closest('button'); if(!b)return; if(b.dataset.delta){const target=b.dataset.target, delta=parseInt(b.dataset.delta,10)||0; if(target==='normal') setTimes(currentNormal+delta,currentExtra); if(target==='extra') setTimes(currentNormal,currentExtra+delta);} if(b.dataset.mediaId){const id=b.dataset.mediaId; selectedMedia=selectedMedia.includes(id)?selectedMedia.filter(x=>x!==id):[...selectedMedia,id]; renderSelectedMedia(); renderLibrary();} if(b.dataset.removeMedia){selectedMedia=selectedMedia.filter(x=>x!==b.dataset.removeMedia); renderSelectedMedia(); renderLibrary();} if(b.dataset.recEdit) fillForm(state.records.find(r=>r.id===b.dataset.recEdit)); if(b.dataset.recDelete&&confirm('削除しますか？')){state.records=state.records.filter(r=>r.id!==b.dataset.recDelete);saveLocal();renderAll();} if(b.dataset.personRecord){$('#personSelect').value=b.dataset.personRecord; applyPerson(b.dataset.personRecord); setTab('record');} if(b.dataset.personEdit){$('#personSelect').value=b.dataset.personEdit; applyPerson(b.dataset.personEdit); setTab('record');} if(b.dataset.personDetail) showPersonDetail(b.dataset.personDetail);}); $('#personSelect').onchange=e=>applyPerson(e.target.value); $('#saveBtn').onclick=saveRecord; $('#clearBtn').onclick=clearForm; $('#geoBtn').onclick=geocodeAddress; $('#locBtn').onclick=useLocation; $('#mapBtn').onclick=openMap; $('#mediaSearch').oninput=renderLibrary; $('#mediaKind').onchange=renderLibrary; $('#peopleSearch').oninput=renderPeople; $('#historySearch').oninput=renderHistory; $('#saveBaseBtn').onclick=saveBaseline; $('#exportBtn').onclick=exportJson; $('#importBtn').onclick=()=>$('#importFile').click(); $('#importFile').onchange=e=>{const f=e.target.files[0]; if(f) importJson(f); e.target.value='';}; $('#loginBtn').onclick=()=>auth.signInWithPopup(new firebase.auth.GoogleAuthProvider()).catch(e=>alert(e.message)); $('#logoutBtn').onclick=()=>auth.signOut(); $('#cloudPushBtn').onclick=cloudPush; $('#cloudPullBtn').onclick=cloudPull; $('#saveFirebaseBtn').onclick=()=>{try{state.firebaseConfig=JSON.parse($('#firebaseConfig').value);saveLocal();alert('保存しました。再読み込みします');location.reload();}catch(e){alert('JSONを確認してください');}};}
function init(){clearForm(); bind(); renderAll(); initFirebase();}
document.addEventListener('DOMContentLoaded',init);
